import os
import json
from typing import List, Dict, Any
import numpy as np
from dataclasses import dataclass
import pickle


@dataclass
class Document:
    content: str
    metadata: Dict[str, Any]
    embedding: np.ndarray = None


class SimpleVectorDB:
    def __init__(self):
        self.documents: List[Document] = []
        self.embeddings: np.ndarray = None
    
    def add_documents(self, documents: List[Document]):
        self.documents.extend(documents)
        embeddings = [doc.embedding for doc in documents]
        if self.embeddings is None:
            self.embeddings = np.array(embeddings)
        else:
            self.embeddings = np.vstack([self.embeddings, np.array(embeddings)])
    
    def search(self, query_embedding: np.ndarray, top_k: int = 5) -> List[Document]:
        if self.embeddings is None or len(self.embeddings) == 0:
            return []
        
        similarities = np.dot(self.embeddings, query_embedding) / (
            np.linalg.norm(self.embeddings, axis=1) * np.linalg.norm(query_embedding)
        )
        
        top_indices = np.argsort(similarities)[-top_k:][::-1]
        return [self.documents[i] for i in top_indices]
    
    def save(self, filepath: str):
        with open(filepath, 'wb') as f:
            pickle.dump({'documents': self.documents, 'embeddings': self.embeddings}, f)
    
    def load(self, filepath: str):
        with open(filepath, 'rb') as f:
            data = pickle.load(f)
            self.documents = data['documents']
            self.embeddings = data['embeddings']


class SimpleEmbedding:
    def __init__(self, dimension: int = 384):
        self.dimension = dimension
        np.random.seed(42)
        self.word_vectors = {}
    
    def _get_word_vector(self, word: str) -> np.ndarray:
        if word not in self.word_vectors:
            np.random.seed(hash(word) % (2**32))
            self.word_vectors[word] = np.random.randn(self.dimension)
            self.word_vectors[word] /= np.linalg.norm(self.word_vectors[word])
        return self.word_vectors[word]
    
    def embed(self, text: str) -> np.ndarray:
        words = text.lower().split()
        if not words:
            return np.zeros(self.dimension)
        
        word_embeddings = [self._get_word_vector(word) for word in words]
        embedding = np.mean(word_embeddings, axis=0)
        embedding /= np.linalg.norm(embedding)
        return embedding


class SimpleLLM:
    def generate(self, prompt: str, max_length: int = 500) -> str:
        response = f"Based on the provided context, here is the answer:\n\n"
        response += "This is a simulated LLM response. In production, this would call an actual LLM API "
        response += "(like OpenAI GPT, Anthropic Claude, or a local model). "
        response += "The response would be generated based on the context and query provided in the prompt."
        return response


class RAGSystem:
    def __init__(self, embedding_model=None, llm=None, vector_db=None):
        self.embedding_model = embedding_model or SimpleEmbedding()
        self.llm = llm or SimpleLLM()
        self.vector_db = vector_db or SimpleVectorDB()
    
    def load_documents(self, documents: List[Dict[str, Any]]):
        doc_objects = []
        for doc in documents:
            content = doc.get('content', '')
            metadata = doc.get('metadata', {})
            
            embedding = self.embedding_model.embed(content)
            doc_obj = Document(content=content, metadata=metadata, embedding=embedding)
            doc_objects.append(doc_obj)
        
        self.vector_db.add_documents(doc_objects)
    
    def load_documents_from_files(self, directory: str):
        documents = []
        for filename in os.listdir(directory):
            filepath = os.path.join(directory, filename)
            if os.path.isfile(filepath):
                with open(filepath, 'r', encoding='utf-8') as f:
                    content = f.read()
                    documents.append({
                        'content': content,
                        'metadata': {'filename': filename, 'filepath': filepath}
                    })
        self.load_documents(documents)
    
    def retrieve_context(self, query: str, top_k: int = 5) -> List[Document]:
        query_embedding = self.embedding_model.embed(query)
        return self.vector_db.search(query_embedding, top_k=top_k)
    
    def create_prompt(self, query: str, context_documents: List[Document]) -> str:
        prompt = "You are a helpful assistant answering questions based on company documents.\n\n"
        prompt += "Context Documents:\n"
        prompt += "=" * 80 + "\n\n"
        
        for i, doc in enumerate(context_documents, 1):
            prompt += f"Document {i}:\n"
            prompt += f"Source: {doc.metadata.get('filename', 'Unknown')}\n"
            prompt += f"Content:\n{doc.content}\n"
            prompt += "-" * 80 + "\n\n"
        
        prompt += "=" * 80 + "\n\n"
        prompt += f"User Question: {query}\n\n"
        prompt += "Please provide a comprehensive answer based on the context documents above. "
        prompt += "If the information is not available in the documents, please state that clearly.\n\n"
        prompt += "Answer:"
        
        return prompt
    
    def query(self, query: str, top_k: int = 5) -> Dict[str, Any]:
        retrieved_docs = self.retrieve_context(query, top_k=top_k)
        
        prompt = self.create_prompt(query, retrieved_docs)
        
        response = self.llm.generate(prompt)
        
        return {
            'query': query,
            'answer': response,
            'retrieved_documents': [
                {
                    'content': doc.content,
                    'metadata': doc.metadata
                }
                for doc in retrieved_docs
            ],
            'prompt': prompt
        }
    
    def save_vector_db(self, filepath: str):
        self.vector_db.save(filepath)
    
    def load_vector_db(self, filepath: str):
        self.vector_db.load(filepath)


